    { id: 58, difficulty: "dificil", question: { pt: "O que causa o sopro cardíaco?", es: "¿Qué causa soplos?" }, answer: { pt: "Fluxo sanguíneo turbulento devido a estenose ou insuficiência valvar.", es: "Flujo turbulento valvular." } },
    { id: 59, difficulty: "dificil", question: { pt: "O que é a hipertrofia excêntrica vs concêntrica?", es: "¿Hipertrofia?" }, answer: { pt: "Excêntrica: por sobrecarga de volume (série); Concêntrica: por sobrecarga de pressão (paralelo).", es: "Volumen vs Presión." } },
    { id: 60, difficulty: "dificil", question: { pt: "O que é a zona de condução 'vulnerável' no ECG?", es: "¿Zona vulnerable?" }, answer: { pt: "Onda T (repolarização); um estímulo nesse ponto pode causar arritmias graves (fenômeno R sobre T).", es: "Onda T (riesgo arritmia)." } }
